135â†’private val PostListDiffItemCallback = object : DiffUtil.ItemCallback<PostListItemType>() {
136â†’    override fun areItemsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
137â†’        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
138â†’            return true
139â†’        }
140â†’        if (oldItem is LoadingItem && newItem is LoadingItem) {
141â†’            return oldItem.localOrRemoteId == newItem.localOrRemoteId
142â†’        }
143â†’        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
144â†’            return oldItem.data.localPostId == newItem.data.localPostId
145â†’        }
146â†’        if (oldItem is LoadingItem && newItem is PostListItemUiState) {
147â†’            return when (oldItem.localOrRemoteId) {
148â†’                is LocalId -> oldItem.localOrRemoteId == newItem.data.localPostId.id
149â†’                is RemoteId -> oldItem.localOrRemoteId == newItem.data.remotePostId.id
150â†’            }
151â†’        }
152â†’        return false
153â†’    }
154â†’
155â†’    override fun areContentsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
156â†’        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
157â†’            return true
158â†’        }
159â†’        if (oldItem is LoadingItem && newItem is LoadingItem) {
160â†’            return when (oldItem.localOrRemoteId) {
161â†’                is LocalId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? LocalId)?.value
162â†’                is RemoteId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? RemoteId)?.value
163â†’            }
164â†’        }
165â†’        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
166â†’            return oldItem.data == newItem.data
167â†’        }
168â†’        return false
169â†’    }
170â†’
171â†’    override fun getChangePayload(oldItem: PostListItemType, newItem: PostListItemType): Any? {
172â†’        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
173â†’            /**
174â†’             * Suppresses the default animation if the progress has changed to prevent blinking as the upload progresses
175â†’             *
176â†’             * We don't need to use the payload in onBindViewHolder unless we want to. Passing a non-null value
177â†’             * suppresses the default ItemAnimator, which is all we need in this case.
178â†’             */
179â†’            if (oldItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
180â†’                newItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
181â†’                oldItem.data.progressBarUiState.progress != newItem.data.progressBarUiState.progress
182â†’            ) {
183â†’                return true
184â†’            }
185â†’        }
186â†’        return super.getChangePayload(oldItem, newItem)
187â†’    }
188â†’}
