563â†’        Map<String, Object> properties = new HashMap<>();
564â†’        if (context == null) {
565â†’            AppLog.e(AppLog.T.MEDIA, "In order to track media properties Context cannot be null.");
566â†’            return properties;
567â†’        }
568â†’        if (mediaURI == null && TextUtils.isEmpty(path)) {
