570â†’            return properties;
571â†’        }
572â†’
573â†’        if (mediaURI != null) {
574â†’            path = MediaUtils.getRealPathFromURI(context, mediaURI);
575â†’        }
576â†’
577â†’        if (TextUtils.isEmpty(path)) {
578â†’            return properties;
579â†’        }
580â†’
581â†’        // File not found
582â†’        File file = new File(path);
583â†’        try {
584â†’            if (!file.exists()) {
585â†’                AppLog.e(AppLog.T.MEDIA,
586â†’                        "Can't access the media file. It doesn't exists anymore!! Properties are not being tracked.");
587â†’                return properties;
588â†’            }
589â†’
590â†’            if (file.lastModified() > 0L) {
