592â†’                properties.put("age_ms", ageMS);
593â†’            }
594â†’        } catch (SecurityException e) {
595â†’            AppLog.e(AppLog.T.MEDIA, "Can't access the media file. Properties are not being tracked.", e);
596â†’            return properties;
597â†’        }
598â†’
599â†’        String mimeType = MediaUtils.getMediaFileMimeType(file);
600â†’        properties.put("mime", mimeType);
601â†’
602â†’        String fileName = MediaUtils.getMediaFileName(file, mimeType);
603â†’        String fileExtension = MimeTypeMap.getFileExtensionFromUrl(fileName).toLowerCase(Locale.ROOT);
604â†’        properties.put("ext", fileExtension);
605â†’
606â†’        if (!isVideo) {
607â†’            int[] dimensions = ImageUtils.getImageSize(Uri.fromFile(file), context);
608â†’            double megapixels = dimensions[0] * dimensions[1];
609â†’            megapixels = megapixels / 1000000;
610â†’            megapixels = Math.floor(megapixels);
