 822â†’    private static boolean getShowGutenbergInfoPopupForTheNewPosts(PrefKey key, String siteURL) {
 823â†’        if (TextUtils.isEmpty(siteURL)) {
 824â†’            return false;
 825â†’        }
 826â†’
 827â†’        Set<String> urls;
 828â†’        try {
 829â†’            urls = prefs().getStringSet(key.name(), null);
 830â†’        } catch (ClassCastException exp) {
 831â†’            // no operation - This should not happen.
 832â†’            return false;
 833â†’        }
 834â†’        // Check if the current site address is available in the set.
 835â†’        boolean flag = false;
 836â†’        if (urls != null) {
 837â†’            if (urls.contains(siteURL)) {
 838â†’                flag = true;
 839â†’                // remove the flag from Prefs
 840â†’                setShowGutenbergInfoPopupForTheNewPosts(key, siteURL, false);
 841â†’            }
 842â†’        }
 843â†’
 844â†’        return flag;
 845â†’    }
 846â†’
 847â†’    private static void setShowGutenbergInfoPopupForTheNewPosts(PrefKey key, String siteURL, boolean show) {
 848â†’        if (TextUtils.isEmpty(siteURL)) {
 849â†’            return;
 850â†’        }
 851â†’        Set<String> urls;
 852â†’        try {
 853â†’            urls = prefs().getStringSet(key.name(), null);
 854â†’        } catch (ClassCastException exp) {
 855â†’            // nope - this should never happens
 856â†’            return;
 857â†’        }
 858â†’
 859â†’        Set<String> newUrls = new HashSet<>();
 860â†’        // re-add the old urls here
 861â†’        if (urls != null) {
 862â†’            newUrls.addAll(urls);
 863â†’        }
 864â†’
 865â†’        // 1. First remove & 2. add if necessary
 866â†’        newUrls.remove(siteURL);
 867â†’        if (show) {
 868â†’            newUrls.add(siteURL);
 869â†’        }
 870â†’
 871â†’        SharedPreferences.Editor editor = prefs().edit();
 872â†’        editor.putStringSet(key.name(), newUrls);
 873â†’        editor.apply();
 874â†’    }
