1025â†’    /*
1026â†’     * adds a local site ID to the top of list of recently chosen sites
1027â†’     */
1028â†’    public static void addRecentlyPickedSiteId(Integer localId) {
1029â†’        if (localId == 0) {
1030â†’            return;
1031â†’        }
1032â†’
1033â†’        ArrayList<Integer> currentIds = getRecentlyPickedSiteIds(MAX_RECENTLY_PICKED_SITES_TO_SAVE);
1034â†’
1035â†’        // remove this ID if it already exists in the list
1036â†’        int index = currentIds.indexOf(localId);
1037â†’        if (index > -1) {
1038â†’            currentIds.remove(index);
1039â†’        }
1040â†’
1041â†’        // add this ID to the front of the list
1042â†’        currentIds.add(0, localId);
1043â†’
1044â†’        // remove at max
1045â†’        if (currentIds.size() > MAX_RECENTLY_PICKED_SITES_TO_SAVE) {
1046â†’            currentIds.remove(MAX_RECENTLY_PICKED_SITES_TO_SAVE);
1047â†’        }
1048â†’
1049â†’        // store in prefs
1050â†’        String idsAsString = TextUtils.join(",", currentIds);
1051â†’        setString(DeletablePrefKey.RECENTLY_PICKED_SITE_IDS, idsAsString);
1052â†’    }
